transform_js:
const categories = [];
const groupA = [];
const groupB = [];
rawData.rows.forEach(r => {
  categories.push(r.category);
  groupA.push(r.group_a);
  // 左側のバーは負の値として扱うことで逆向きに描画させる
  groupB.push(-Math.abs(r.group_b)); 
});
// 下から上に向かって年齢が高くなるのが一般的なためリバース
transformedData = { categories: categories.reverse(), groupA: groupA.reverse(), groupB: groupB.reverse() };

echarts_js:
option = {
  title: {
    text: 'Population Pyramid (Butterfly Chart)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    formatter: function(params) {
       let res = params[0].name + '<br/>';
       params.forEach(p => {
          // 左側用にマイナスにした値を絶対値に戻して表示
          res += p.marker + p.seriesName + ': ' + Math.abs(p.value) + '<br/>';
       });
       return res;
    }
  },
  legend: {
    data: ['Male (Left)', 'Female (Right)'],
    bottom: 0
  },
  grid: {
    left: '3%',
    right: '4%',
    bottom: '10%',
    containLabel: true
  },
  xAxis: [
    {
      type: 'value',
      axisLabel: {
         // X軸の目盛りも絶対値で表示
         formatter: function(val) { return Math.abs(val); }
      }
    }
  ],
  yAxis: [
    {
      type: 'category',
      axisTick: { show: false },
      data: transformedData.categories
    }
  ],
  series: [
    {
      name: 'Male (Left)',
      type: 'bar',
      stack: 'Total',
      label: {
        show: true,
        position: 'left',
        formatter: function(params) { return Math.abs(params.value); }
      },
      itemStyle: { color: '#5470c6' },
      data: transformedData.groupB
    },
    {
      name: 'Female (Right)',
      type: 'bar',
      stack: 'Total',
      label: {
        show: true,
        position: 'right'
      },
      itemStyle: { color: '#ee6666' },
      data: transformedData.groupA
    }
  ]
};
